import {
  CalendarOutlined,
  CheckCircleOutlined,
  ClockCircleOutlined,
  EnvironmentOutlined,
  ExclamationCircleOutlined,
  MailOutlined,
  PhoneOutlined,
  SearchOutlined,
  TeamOutlined,
  UserOutlined,
} from "@ant-design/icons"
import {
  Avatar,
  Card,
  Col,
  Divider,
  Image,
  Row,
  Space,
  Tabs,
  Tag,
  Tooltip,
  Typography,
} from "antd"
import PropTypes from "prop-types"
import { useEffect, useMemo, useState } from "react"
import { useSelector } from "react-redux"
import { FloatActionWrapper } from "src/components/FloatAction/styles"
import InputCustom from "src/components/Input/InputCustom"
import CB1 from "src/components/Modal/CB1"
import ButtonCustom from "src/components/MyButton/Button"
import ButtonCircle from "src/components/MyButton/ButtonCircle"
import notice from "src/components/Notice"
import SvgIcon from "src/components/SvgIcon"
import TableCustom from "src/components/Table/CustomTable"
import {
  MainTableData,
  SubTableData,
} from "src/components/Table/CustomTable/styled"
import { SYSTEM_KEY } from "src/constants/constants"
import { getListComboByKey } from "src/lib/utils"
import AssociationService from "src/services/AssociationService"
import FeeManagement from "src/services/FeeManagement"
import { TabsNewsStyled } from "../ListContact/styles"
import "./styles/AssociationCard.scss"
const { Text } = Typography

const { TabPane } = Tabs

const MemberFeeTable = ({ association, defaultTab }) => {
  const [searchText, setSearchText] = useState("")
  const [loading, setLoading] = useState(false)
  const [listData, setListData] = useState({ ListData: [] })
  const [associationDetail, setAssociationDetail] = useState({})
  const [activeTab, setActiveTab] = useState(
    defaultTab || "PAYMENT_STATUS_PAID",
  )
  const [pagination, setPagination] = useState({
    PageSize: 10,
    CurrentPage: 1,
  })
  const [previewVisible, setPreviewVisible] = useState(false)

  const columns = [
    {
      title: "STT",
      key: "stt",
      width: 60,
      align: "center",
      render: (_, __, index) =>
        (pagination.CurrentPage - 1) * pagination.PageSize + index + 1,
    },
    {
      title: (
        <div>
          <MainTableData>Tên Hội Viên</MainTableData>
          <SubTableData style={{ color: "white" }}>Mã Hội Viên</SubTableData>
        </div>
      ),
      key: "UserID",
      align: "center",
      width: 250,
      render: (_, record) => (
        <div>
          <MainTableData className="max-line1">
            {record?.UserName}
          </MainTableData>
          <SubTableData className="fs-13">{record?.UserID}</SubTableData>
        </div>
      ),
    },
    {
      title: "Loại hội viên",
      dataIndex: "PackageName",
      key: "PackageID",
      align: "center",
      width: 120,
    },
    {
      title: "Số tiền",
      dataIndex: "Amount",
      key: "Amount",
      align: "center",
      width: 170,
      render: value =>
        value ? Number(value).toLocaleString("vi-VN") + " ₫" : "",
    },
    {
      title: "Hạn đóng",
      dataIndex: "DueDate",
      key: "DueDate",
      align: "center",
      width: 100,
      render: value =>
        value ? new Date(value).toLocaleDateString("vi-VN") : "",
    },
    {
      title: "Trạng thái",
      dataIndex: "PaymentStatus",
      key: "PaymentStatus",
      align: "center",
      width: 180,
      render: (status, record) => {
        let color = "default"
        let icon = null
        let text = ""
        switch (record.PaymentStatus) {
          case 2:
            color = "green"
            icon = <CheckCircleOutlined />
            text = "Đã đóng"
            break
          case 1:
            color = "orange"
            icon = <ClockCircleOutlined />
            text = "Chưa đóng"
            break
          case 3:
            color = "red"
            icon = <ExclamationCircleOutlined />
            text = "Quá hạn"
            break
          default:
            text = "Không xác định"
        }

        const showApprove = status === 1 || status === 3

        return (
          <div
            style={{
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              gap: 8,
            }}
          >
            <Tag color={color} icon={icon} style={{ fontSize: 15, margin: 0 }}>
              {text}
            </Tag>
            {showApprove && (
              <FloatActionWrapper
                size="small"
                className="float-action__wrapper"
              >
                <ButtonCircle
                  title="Duyệt"
                  iconName="check-circle"
                  style={{ background: "#EDF6FC" }}
                  onClick={e => {
                    e.stopPropagation()
                    CB1({
                      title: "Bạn có chắc chắn muốn duyệt bản ghi này không?",
                      icon: "signSuccess",
                      okText: "Đồng ý",
                      onOk: async close => {
                        try {
                          setLoading(true)
                          const res =
                            await FeeManagement.postConfirmFeeAssignment({
                              FeeAssignmentID: record.FeeAssignmentID,
                            })
                          if (res?.isOk) {
                            notice({ msg: "Xác nhận đã đóng thành công." })
                            await getList()
                          } else {
                            notice({
                              msg: "Xác nhận đã đóng thất bại!",
                              isSuccess: false,
                            })
                          }
                        } catch (err) {
                          console.error("Duyệt thất bại:", err)
                          notice({
                            msg: "Có lỗi xảy ra khi duyệt!",
                            isSuccess: false,
                          })
                        } finally {
                          setLoading(false)
                          close()
                        }
                      },
                    })
                  }}
                />
              </FloatActionWrapper>
            )}
          </div>
        )
      },
    },
  ]

  const { listSystemKey } = useSelector(state => state.appGlobal)

  const paymentStatusList = useMemo(
    () => getListComboByKey(SYSTEM_KEY.PAYMENT_STATUS, listSystemKey) || [],
    [listSystemKey],
  )

  console.log("...",paymentStatusList)

  const filteredData = useMemo(() => {
    const list = listData?.ListData || []
    if (!paymentStatusList.length) return list // Chưa sẵn sàng
    const selectedStatus = paymentStatusList.find(s => s.CodeKey === activeTab)
    if (!selectedStatus) return list
    return list.filter(
      member => member.PaymentStatus === selectedStatus.CodeValue,
    )
  }, [listData, activeTab, paymentStatusList])

  const groupedCounts = useMemo(() => {
    const list = listData?.ListData || []
    const counts = {}
    paymentStatusList.forEach(status => {
      counts[status.CodeKey] = list.filter(
        m => m.PaymentStatus === status.CodeValue,
      ).length
    })
    return counts
  }, [listData, paymentStatusList])

  const getList = async () => {
    try {
      setLoading(true)
      const params = {
        AssociationID: association.AssociationID,
        TextSearch: searchText,
      }
      const res = await FeeManagement.getListFeeAssignment(params)
      if (!res?.isError) setListData(res?.Object)
    } catch (error) {
      console.log("error>>getList:", error)
    } finally {
      setLoading(false)
    }
  }

  const getAssociationDetail = async () => {
    try {
      setLoading(true)
      const params = {
        AssociationID: association.AssociationID,
      }
      const res = await AssociationService.getAssociationDetail(params)
      if (!res?.isError) setAssociationDetail(res?.Object)
    } catch (error) {
      console.log("error>>getList:", error)
    } finally {
      setLoading(false)
    }
  }

  const handleExport = () => {
    console.log("Xuất dữ liệu:", filteredData)
    // Logic xuất Excel ở đây
  }

  useEffect(() => {
    if (association?.AssociationID) {
      getList()
      getAssociationDetail()
    }
  }, [association?.AssociationID, searchText])

  return (
    <Row gutter={24}>
      {/* Left: Association Detail */}
      <Col span={6}>
        <Card
          title={
            <Space className="card-header">
              {associationDetail.Image ? (
                <>
                  <Avatar
                    size={32}
                    style={{ cursor: "pointer" }}
                    src={associationDetail.Image}
                    onClick={() => setPreviewVisible(true)}
                  />
                  <Image
                    src={associationDetail.Image}
                    preview={{
                      visible: previewVisible,
                      onVisibleChange: vis => setPreviewVisible(vis),
                    }}
                    style={{ display: "none" }}
                  />
                </>
              ) : (
                <Avatar size={32}>
                  {associationDetail.AssociationName?.charAt(0) || "H"}
                </Avatar>
              )}
              <span className="title">{associationDetail.AssociationName}</span>
            </Space>
          }
          size="small"
          headStyle={{
            background: "linear-gradient(90deg, #FFF7E6 0%, #FFEFD5 100%)",
            borderRadius: "12px 12px 0 0",
            padding: "16px",
          }}
          bodyStyle={{
            fontSize: 13,
            padding: "16px",
            background: "#FFFFFF",
          }}
          style={{
            borderRadius: 12,
            boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
            height: "100%",
            border: "1px solid #f0f0f0",
            transition: "transform 0.3s ease, box-shadow 0.3s ease",
          }}
          className="association-card"
        >
          <div className="code-section" style={{ marginBottom: 12 }}>
            <Text type="secondary" className="label">
              Mã chi hội:
            </Text>{" "}
            <Text strong className="code">
              {associationDetail.AssociationCode}
            </Text>
          </div>

          <Divider className="divider" />

          <Row gutter={[0, 12]}>
            <Col span={24}>
              <Row>
                <Col span={12}>
                  <Text>
                    <EnvironmentOutlined className="icon" /> Địa chỉ:
                  </Text>
                </Col>
                <Col span={12}>
                  <Tooltip title={associationDetail.Address}>
                    <Text
                      ellipsis
                      style={{ maxWidth: "100%", display: "inline-block" }}
                    >
                      {associationDetail.Address}
                    </Text>
                  </Tooltip>
                </Col>
              </Row>
            </Col>

            <Col span={24}>
              <Row>
                <Col span={12}>
                  <Text>
                    <MailOutlined className="icon" /> Email:
                  </Text>
                </Col>
                <Col span={12}>
                  <Tooltip title={associationDetail.Email}>
                    <Text
                      ellipsis
                      style={{ maxWidth: "100%", display: "inline-block" }}
                    >
                      {associationDetail.Email}
                    </Text>
                  </Tooltip>
                </Col>
              </Row>
            </Col>

            <Col span={24}>
              <Row>
                <Col span={12}>
                  <Text>
                    <PhoneOutlined className="icon" /> SĐT:
                  </Text>
                </Col>
                <Col span={12}>
                  <Text>{associationDetail.PhoneNumber}</Text>
                </Col>
              </Row>
            </Col>

            <Col span={24}>
              <Row>
                <Col span={12}>
                  <Text>
                    <CalendarOutlined className="icon" /> Ngày thành lập:
                  </Text>
                </Col>
                <Col span={12}>
                  <Text>
                    {new Date(
                      associationDetail.EstablishmentDate,
                    ).toLocaleDateString("vi-VN")}
                  </Text>
                </Col>
              </Row>
            </Col>

            <Col span={24}>
              <Row>
                <Col span={12}>
                  <Text>
                    <TeamOutlined className="icon" /> Tổng hội viên:
                  </Text>
                </Col>
                <Col span={12}>
                  <Text>{associationDetail.MemberNo}</Text>
                </Col>
              </Row>
            </Col>

            <Col span={24}>
              <Row>
                <Col span={12}>
                  <Text>
                    <UserOutlined className="icon" /> Trưởng chi hội:
                  </Text>
                </Col>
                <Col span={12}>
                  <Text>{associationDetail.LeaderName || 'Chưa có'}</Text>
                </Col>
              </Row>
            </Col>
          </Row>

          <Divider className="divider" />
        </Card>
      </Col>

      {/* Right: Table and controls */}
      <Col Col span={18}>
        <Row justify="space-between" align="middle" className="mb-4">
          <Col flex="auto">
            <TabsNewsStyled>
              <Tabs activeKey={activeTab} onChange={setActiveTab}>
                {paymentStatusList.map(status => (
                  <TabPane
                    key={status.CodeKey}
                    tab={`${status.Description} (${
                      groupedCounts[status.CodeKey] || 0
                    })`}
                  />
                ))}
              </Tabs>
            </TabsNewsStyled>
          </Col>
          <Col>
            <Space style={{ marginBottom: 18 }}>
              <InputCustom
                placeholder="Tìm kiếm hội viên..."
                prefix={<SearchOutlined />}
                value={searchText}
                onChange={e => setSearchText(e.target.value)}
                allowClear
                style={{ width: 220 }}
              />
              <ButtonCustom
                type="primary"
                onClick={handleExport}
                icon={<SvgIcon name="uploadVBMIcon" />}
              >
                Xuất Excel
              </ButtonCustom>
            </Space>
          </Col>
        </Row>
        {paymentStatusList.length > 0 && (
          <TableCustom
            columns={columns}
            dataSource={filteredData}
            rowKey="FeeAssignmentID"
            loading={loading}
            pagination={{
              hideOnSinglePage: listData?.total <= 10,
              current: pagination?.CurrentPage,
              pageSize: pagination?.PageSize,
              responsive: true,
              total: listData?.total,
              locale: { items_per_page: "" },
              showSizeChanger: listData?.total > 10,
              onChange: (CurrentPage, PageSize) => {
                setPagination({
                  ...pagination,
                  CurrentPage,
                  PageSize,
                })
              },
            }}
            size="middle"
            rowClassName={record => {
              switch (record.PaymentStatus) {
                case 3:
                  return "row-overdue"
                case 1:
                  return "row-pending"
                default:
                  return ""
              }
            }}
          />
        )}
      </Col>
    </Row>
  )
}

MemberFeeTable.propTypes = {
  association: PropTypes.shape({
    AssociationID: PropTypes.string,
    AssociationName: PropTypes.string,
    AssociationCode: PropTypes.string,
    TotalMembers: PropTypes.number,
    PaidMembers: PropTypes.number,
    UnpaidMembers: PropTypes.number,
    OverdueMembers: PropTypes.number,
  }),
  defaultTab: PropTypes.oneOf([
    "PAYMENT_STATUS_PAID",
    "PAYMENT_STATUS_UNPAID",
    "PAYMENT_STATUS_OVERDUE",
  ]),
}

export default MemberFeeTable
