import { useEffect, useState } from "react";
import SpinCustom from "src/components/SpinCustom";
import STORAGE, { getStorage } from "src/lib/storage";
import AssociationList from "./AssociationList";
// import ChapterDetailDrawer from "./ChapterDetailDrawer";
import "./styles/index.scss";

const App = () => {
  const [loading,] = useState(false);
  const [renderComponent, setRenderComponent] = useState(null);

  useEffect(() => {
    const userInfo = getStorage(STORAGE.USER_INFO);
    if (!userInfo) return;

    const role = userInfo.RoleType;
    console.log("RoleType:", userInfo);

    switch (role) {
      // case 9:
      //   // setRenderComponent(<AssociationList />);
      //   break;

      // case 3: // ví dụ role khác, bạn có thể bổ sung ở đây
      //   // setRenderComponent(<ChapterDetailDrawer ... />)
      //   break;

      default:
        setRenderComponent(<AssociationList />);
    }
  }, []);

  return (
    <SpinCustom spinning={loading}>
      {renderComponent}
    </SpinCustom>
  );
};

export default App;
