import {
  CheckCircleOutlined,
  ClockCircleOutlined,
  ExclamationCircleOutlined,
} from "@ant-design/icons"
import { Card, Col, Progress, Row } from "antd"
import { useEffect, useState } from "react"
import SpinCustom from "src/components/SpinCustom"
import SvgIcon from "src/components/SvgIcon"
import TableCustom from "src/components/Table/CustomTable"
import {
  MainTableData,
  SubTableData,
} from "src/components/Table/CustomTable/styled"
import TitleCustom from "src/components/TitleCustom"
import FeeManagement from "src/services/FeeManagement"
import ChapterDetailDrawer from "./ChapterDetailDrawer"
import "./styles/index.scss"

const AssociationList = () => {
  const [loading, setLoading] = useState(false)
  const [listData, setListData] = useState([])
  const [selectedChapter, setSelectedChapter] = useState(null)
  const [defaultTab, setDefaultTab] = useState("PAYMENT_STATUS_PAID")
  const [pagination, setPagination] = useState({
    PageSize: 20,
    CurrentPage: 1,
  })

  const getTotalStats = () => ({
    TotalAssociation: listData?.TotalAssociation || 0,
    TotalMembers: listData?.TotalMembers || 0,
    TotalPaidMembers: listData?.TotalPaidMembers || 0,
    TotalUnpaidMembers: listData?.TotalUnpaidMembers || 0,
    TotalOverdueMembers: listData?.TotalOverdueMembers || 0,
  })

  const totalStats = getTotalStats()

  const handleOpenDrawerWithTab = (chapter, tabKey) => {
    setDefaultTab(tabKey)
    setSelectedChapter(chapter)
  }

  const chapterColumns = [
    {
      title: "STT",
      key: "stt",
      width: 30,
      align: "center",
      render: (_, __, index) =>
        (pagination.CurrentPage - 1) * pagination.PageSize + index + 1,
    },
    {
      title: (
        <div>
          <MainTableData>Tên Chi Hội</MainTableData>
          <SubTableData style={{ color: "white" }}>Mã Chi Hội</SubTableData>
        </div>
      ),
      key: "maChiHoi",
      align: "center",
      width: 140,
      className: "colNameBranch",
      sorter: (a, b) =>
        (a.AssociationName || "").localeCompare(b.AssociationName || ""),
      render: (value, record) => (
        <div>
          <MainTableData className="max-line1">
            {record?.AssociationName || "-"}
          </MainTableData>
          <SubTableData className="fs-13">
            {record?.AssociationCode || "-"}
          </SubTableData>
        </div>
      ),
    },
    {
      title: "Tổng hội viên",
      dataIndex: "TotalMembers",
      key: "TotalMembers",
      width: 120,
      align: "center",
      render: value => <strong>{value?.toLocaleString("vi-VN")}</strong>,
    },
    {
      title: (
        <span>
          <CheckCircleOutlined style={{ marginRight: 4 }} />
          Đã thanh toán
        </span>
      ),
      dataIndex: "PaidMembers",
      key: "PaidMembers",
      width: 100,
      align: "center",
      render: value => (
        <span style={{ color: "green", fontWeight: "bold" }}>
          {value?.toLocaleString("vi-VN")}
        </span>
      ),
      onCell: record => ({
        onClick: e => {
          e.stopPropagation()
          handleOpenDrawerWithTab(record, "PAYMENT_STATUS_PAID")
        },
        style: { cursor: "pointer" },
      }),
    },
    {
      title: (
        <span>
          <ClockCircleOutlined style={{ marginRight: 4 }} />
          Chưa thanh toán
        </span>
      ),
      dataIndex: "UnpaidMembers",
      key: "UnpaidMembers",
      width: 100,
      align: "center",
      render: value => (
        <span style={{ color: "orange", fontWeight: "bold" }}>
          {value?.toLocaleString("vi-VN")}
        </span>
      ),
      onCell: record => ({
        onClick: e => {
          e.stopPropagation()
          handleOpenDrawerWithTab(record, "PAYMENT_STATUS_UNPAID")
        },
        style: { cursor: "pointer" },
      }),
    },
    {
      title: (
        <span>
          <ExclamationCircleOutlined style={{ marginRight: 4 }} />
          Quá hạn
        </span>
      ),
      dataIndex: "OverdueMembers",
      key: "OverdueMembers",
      width: 100,
      align: "center",
      render: value => (
        <span style={{ color: "red", fontWeight: "bold" }}>
          {value?.toLocaleString("vi-VN")}
        </span>
      ),
      onCell: record => ({
        onClick: e => {
          e.stopPropagation()
          handleOpenDrawerWithTab(record, "PAYMENT_STATUS_OVERDUE")
        },
        style: { cursor: "pointer" },
      }),
    },
    {
      title: "Tỷ lệ hoàn thành",
      key: "tyLeHoanThanh",
      width: 100,
      align: "center",
      render: (_, record) => {
        const { PaidMembers, TotalMembers } = record
        const percent =
          TotalMembers > 0 ? (PaidMembers / TotalMembers) * 100 : 0
        const rounded = parseFloat(percent.toFixed(2))
        const isFull = rounded === 100

        return (
          <div className={`progress-container ${isFull ? "full" : ""}`}>
            <Progress
              percent={rounded}
              size="small"
              showInfo={false}
              strokeColor={
                isFull
                  ? "#52c41a"
                  : {
                      from: "#A0E9A3",
                      to: "#52c41a",
                    }
              }
              trailColor="#f0f0f0"
            />
            <div className="progress-text">{rounded}%</div>
          </div>
        )
      },
    },
  ]

  const getList = async () => {
    try {
      setLoading(true)
      const res = await FeeManagement.getListAssociationWithDueTracking()
      console.log("res: ", res)
      if (res?.isError) return
      setListData(res?.Object)
    } catch (error) {
      console.log("error>>getList:", error)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    getList()
  }, [pagination])

  return (
    <SpinCustom spinning={loading}>
      <div className="p-4">
        {selectedChapter ? (
          <div className="mt-6">
            <div className="mt-6">
              <ChapterDetailDrawer
                chapter={selectedChapter}
                defaultTab={defaultTab}
                onBack={() => setSelectedChapter(null)}
              />
            </div>
          </div>
        ) : (
          <>
            <div className="mb-4">
              <TitleCustom className="mb-3">
                Quản lý chi hội và hội viên
              </TitleCustom>
              <Row gutter={[16, 16]} className="dashboard-summary">
                {[
                  {
                    title: "Tổng chi hội",
                    value: totalStats.TotalAssociation,
                    icon: <SvgIcon name="management-skdn" />,
                    gradient: "linear-gradient(135deg, #FDBA74, #FB923C)",
                  },
                  {
                    title: "Tổng hội viên",
                    value: totalStats.TotalMembers,
                    icon: <SvgIcon name="person" />,
                    gradient: "linear-gradient(135deg, #FCA5A5, #F87171)",
                  },
                  {
                    title: "Đã đóng phí",
                    value: totalStats.TotalPaidMembers,
                    icon: <SvgIcon name="green-accept" />,
                    color: "#22C55E",
                    gradient: "linear-gradient(135deg, #86EFAC, #4ADE80)",
                  },
                  {
                    title: "Chưa đóng phí",
                    value: totalStats.TotalUnpaidMembers,
                    icon: <SvgIcon name="access-time" />,
                    color: "#FBBF24",
                    gradient: "linear-gradient(135deg, #FDE68A, #FACC15)",
                  },
                  {
                    title: "Quá hạn",
                    value: totalStats.TotalOverdueMembers,
                    icon: <SvgIcon name="warningAmber" />,
                    color: "#DC2626",
                    gradient: "linear-gradient(135deg, #FCA5A5, #EF4444)",
                  },
                ].map((item, index) => (
                  <Col key={index} flex="1" className="mt-6 mb-6">
                    <Card
                      className="summary-card-glass"
                      bodyStyle={{ padding: 16 }}
                    >
                      <Row align="middle" gutter={12} className="ml-12">
                        <Col>
                          <div
                            className="summary-icon-glass"
                            style={{ background: item.gradient }}
                          >
                            {item.icon}
                          </div>
                        </Col>
                        <Col>
                          <div className="summary-title">{item.title}</div>
                          <div
                            className="summary-value"
                            style={{ color: item.color }}
                          >
                            {item.value.toLocaleString()}
                          </div>
                        </Col>
                      </Row>
                    </Card>
                  </Col>
                ))}
              </Row>
            </div>

            {/* Bảng danh sách chi hội */}
            <TableCustom
              columns={chapterColumns}
              dataSource={listData?.Associations}
              rowKey="id"
              pagination={{
                hideOnSinglePage: listData?.total <= 10,
                current: pagination?.CurrentPage,
                pageSize: pagination?.PageSize,
                responsive: true,
                total: listData?.total,
                locale: { items_per_page: "" },
                showSizeChanger: listData?.total > 10,
                onChange: (CurrentPage, PageSize) => {
                  setPagination({
                    ...pagination,
                    CurrentPage,
                    PageSize,
                  })
                },
              }}
              className="tableBranch"
              scroll={{ x: 1000 }}
              size="middle"
              onRow={record => ({
                onClick: () => setSelectedChapter(record),
              })}
            />
          </>
        )}
      </div>
    </SpinCustom>
  )
}

export default AssociationList
