import { ArrowLeftOutlined } from "@ant-design/icons";
import { Card, Col, Row } from "antd";
import PropTypes from "prop-types";
import ButtonCustom from "src/components/MyButton/Button";
import SvgIcon from "src/components/SvgIcon";
import TitleCustom from "src/components/TitleCustom";
import STORAGE, { getStorage } from "src/lib/storage";
import MemberFeeTable from "./MemberFeeTable";

const ChapterDetailDrawer = ({ chapter, defaultTab, onBack }) => {
  if (!chapter) return null;

  return (
    <div className="chapter-detail-container">
      <div className="mb-4">
        <TitleCustom className="mb-3 d-flex-sb" style={{ alignItems: "center" }}>
          <span>
            Danh sách hội viên - {chapter?.AssociationName} ({chapter?.AssociationCode})
          </span>
          <div className="d-flex-end">
            {getStorage(STORAGE.USER_INFO)?.RoleType === 9 && (
              <div className="d-flex-end mb-3">
                <ButtonCustom
                  icon={<ArrowLeftOutlined />}
                  onClick={onBack}
                >
                  Back
                </ButtonCustom>
              </div>
            )}

          </div>
        </TitleCustom>

        <Row gutter={[16, 16]} className="dashboard-summary mb-6 mt-6">
          {[
            {
              title: "Tổng hội viên",
              value: chapter?.TotalMembers || 0,
              icon: <SvgIcon name="person-seminar" />,
              color: "#3B82F6",
              gradient: "linear-gradient(135deg, #93C5FD, #3B82F6)",
            },
            {
              title: "Đã đóng",
              value: chapter?.PaidMembers || 0,
              icon: <SvgIcon name="green-accept" />,
              color: "#22C55E",
              gradient: "linear-gradient(135deg, #86EFAC, #4ADE80)",
            },
            {
              title: "Chưa đóng",
              value: chapter?.UnpaidMembers || 0,
              icon: <SvgIcon name="access-time" />,
              color: "#F59E0B",
              gradient: "linear-gradient(135deg, #FDE68A, #FBBF24)",
            },
            {
              title: "Quá hạn",
              value: chapter?.OverdueMembers || 0,
              icon: <SvgIcon name="warningAmber" />,
              color: "#EF4444",
              gradient: "linear-gradient(135deg, #FCA5A5, #EF4444)",
            },
          ].map((item, index) => (
            <Col key={index} xs={24} sm={12} md={6}>
              <Card className="summary-card-glass" bodyStyle={{ padding: 16 }}>
                <Row align="middle" gutter={12} className="ml-12">
                  <Col>
                    <div
                      className="summary-icon-glass"
                      style={{ background: item.gradient }}
                    >
                      {item.icon}
                    </div>
                  </Col>
                  <Col>
                    <div className="summary-title">{item.title}</div>
                    <div className="summary-value" style={{ color: item.color }}>
                      {item.value.toLocaleString("vi-VN")}
                    </div>
                  </Col>
                </Row>
              </Card>
            </Col>
          ))}
        </Row>
      </div>

      <MemberFeeTable association={chapter} defaultTab={defaultTab} />
    </div>
  );
};

ChapterDetailDrawer.propTypes = {
  chapter: PropTypes.shape({
    AssociationName: PropTypes.string,
    AssociationCode: PropTypes.string,
    TotalMembers: PropTypes.number,
    PaidMembers: PropTypes.number,
    UnpaidMembers: PropTypes.number,
    OverdueMembers: PropTypes.number,
  }),
  defaultTab: PropTypes.oneOf([
    "PAYMENT_STATUS_PAID",
    "PAYMENT_STATUS_UNPAID",
    "PAYMENT_STATUS_OVERDUE",
  ]),
  onBack: PropTypes.func.isRequired,
};

ChapterDetailDrawer.defaultProps = {
  chapter: null,
  defaultTab: "PAYMENT_STATUS_PAID",
};

export default ChapterDetailDrawer;
